1	import { describe, it, expect } from "vitest";
2	import { execute } from "./mars-rover.js";
3	
4	describe("Mars Rover", () => {
5	  it("should return the initial position and heading for an empty command string", () => {
6	    expect(execute("")).toBe("0:0:N");
7	  });
8	  it("should rotate left from north to west", () => {
9	    expect(execute("L")).toBe("0:0:W");
10	  });
11	  it("should rotate right from north to east", () => {
12	    expect(execute("R")).toBe("0:0:E");
13	  });
14	  it("should move forward one square when facing north", () => {
15	    expect(execute("F")).toBe("0:1:N");
16	  });
17	  it("should move forward one square when facing east", () => {
18	    expect(execute("RF")).toBe("1:0:E");
19	  });
20	  it("should move forward one square when facing south", () => {
21	    expect(execute("RRF")).toBe("0:-1:S");
22	  });
23	  it("should move forward one square when facing west", () => {
24	    expect(execute("LF")).toBe("-1:0:W");
25	  });
26	  it("should rotate left through all four headings (N->W->S->E->N)", () => {
27	    expect(execute("LLLL")).toBe("0:0:N");
28	  });
29	  it("should rotate right through all four headings (N->E->S->W->N)", () => {
30	    expect(execute("RRRR")).toBe("0:0:N");
31	  });
32	  it.todo("should execute a sequence of commands in order");
33	});
