1	type Heading = "N" | "E" | "S" | "W";
2	type State = { x: number; y: number; heading: Heading };
3	
4	const LEFT_OF: Record<Heading, Heading> = { N: "W", W: "S", S: "E", E: "N" };
5	const RIGHT_OF: Record<Heading, Heading> = { N: "E", E: "S", S: "W", W: "N" };
6	const FORWARD_DELTA: Record<Heading, [number, number]> = {
7	  N: [0, 1],
8	  E: [1, 0],
9	  S: [0, -1],
10	  W: [-1, 0],
11	};
12	
13	const COMMANDS: Record<string, (state: State) => State> = {
14	  L: ({ x, y, heading }) => ({ x, y, heading: LEFT_OF[heading] }),
15	  R: ({ x, y, heading }) => ({ x, y, heading: RIGHT_OF[heading] }),
16	  F: ({ x, y, heading }) => {
17	    const [dx, dy] = FORWARD_DELTA[heading];
18	    return { x: x + dx, y: y + dy, heading };
19	  },
20	};
21	
22	const INITIAL_STATE: State = { x: 0, y: 0, heading: "N" };
23	
24	export function execute(commands: string): string {
25	  const { x, y, heading } = [...commands].reduce(
26	    (state, command) => COMMANDS[command](state),
27	    INITIAL_STATE,
28	  );
29	  return `${x}:${y}:${heading}`;
30	}
